const today = new Date();
const yesterday = new Date(today.getTime() - 24*60*60*1000);
const sources = [
  {name:'YourStory', searchUrl:'https://yourstory.com/search?q=funding'},
  {name:'Inc42', searchUrl:'https://inc42.com/?s=funding'},
  {name:'Entrackr', searchUrl:'https://entrackr.com/?s=funding'},
  {name:'GoogleNews', searchUrl:'https://news.google.com/search?q=indian%20startup%20funding%202025%202026&hl=en-IN&gl=IN&ceid=IN:en'},
  {name:'IndianStartupNews', searchUrl:'https://indianstartupnews.com/?s=funding'},
  {name:'The Economic Times', searchUrl:'https://economictimes.indiatimes.com/topic/startup-funding'},
  {name:'Mint', searchUrl:'https://www.livemint.com/topic/startups'},
  {name:'Reuters', searchUrl:'https://www.reuters.com/site-search/?query=India startup funding'},
  {name:'Crunchbase', searchUrl:'https://www.crunchbase.com/discover/organization.companies'}
];
return sources.map(s => ({json:{...s, runDate: today.toISOString(), since: yesterday.toISOString()}}));

const html = $json.body || $json.data || $json;

// ✅ Extract all links BEFORE cleaning
const links = [];
const linkMatches = String(html).matchAll(/href="(https?:\/\/[^"]+)"/g);

for (const match of linkMatches) {
  links.push(match[1]);
}

// Optional: remove duplicates
const uniqueLinks = [...new Set(links)].slice(0, 50);

// ✅ Clean readable text
const text = String(typeof html === 'string' ? html : JSON.stringify(html))
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .slice(0, 15000);

// ✅ Return both text + links
return [{
  json: {
    source: $item(0).$node['Build Source List'].json.name,
    sourceUrl: $item(0).$node['Build Source List'].json.searchUrl,
    pageText: text,
    links: uniqueLinks
  }
}];

let raw = $json.text || $json.response || $json.output || '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

// Extract JSON block
const match = raw.match(/\{[\s\S]*\}/);

if (!match) {
  return [];
}

let jsonString = match[0];

// 🔥 CLEAN COMMON LLM ISSUES
jsonString = jsonString
  .replace(/,\s*}/g, '}')        // trailing commas
  .replace(/,\s*]/g, ']')        // trailing commas in arrays
  .replace(/\n/g, ' ')           // remove line breaks
  .replace(/\r/g, ' ')
  .replace(/"\s+"/g, '", "')     // missing comma between strings
  .replace(/"\s*"/g, '", "')     // another fix
  .replace(/([}\]])\s*([{\[])/g, '$1,$2'); // missing comma between objects

let parsed;

try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  // 🔥 fallback: don't break workflow
  return [];
}

// Ensure array
const articles = Array.isArray(parsed.articles) ? parsed.articles : [];

return articles.map(a => ({
  json: a || {}
}));

const originalJson = typeof $json === 'object' && $json !== null ? $json : {};
const startup = $json.startup_name || '';

const founders = ($json.founder_name || startup || '').trim();

const linkedinSearch = `https://www.linkedin.com/search/results/people/?keywords=${encodeURIComponent(founders + ' founder ' + startup)}`;

const slug = startup.toLowerCase().replace(/[^a-z0-9]+/g, '-');

const crunchbaseUrl = `https://www.crunchbase.com/organization/${slug}`;

return {
  json: {
    ...$json,
    founder_name: $json.founder_name || 'Unknown',
    founder_linkedin: linkedinSearch,
    crunchbase_url: crunchbaseUrl
  }
};

function score(item){
  let s = 0;

  const amtRaw = item.amount_raised || '';

  const amt = /(\$|₹|million|crore|billion)/i.test(amtRaw)
    ? amtRaw.toLowerCase()
    : '';

  const round = (item.round_type || '').toLowerCase();

  const desc = ((item.startup_description || '') + ' ' + (item.evidence || '')).toLowerCase();

  if (['pre-seed','seed','series a','series b'].some(x => round.includes(x))) s += 20;

  if (/(million|crore|billion|lakhs|usd|\$|₹)/.test(amt)) s += 15;

  if (/(expand|expansion|hire|hiring|growth|scale|product|engineering|market|team)/.test(desc)) s += 20;

  if (/(ai|saas|fintech|healthtech|deeptech|climate|ev|consumer|enterprise)/.test(desc)) s += 15;

  s += 30;

  const band = s >= 80 ? 'High' : s >= 60 ? 'Likely' : s >= 40 ? 'Watchlist' : 'Low';

  return {score:s, band};
}

const {score: hiring_score, band: hiring_signal} = score($json);

return {
  json: {
    ...$json,
    hiring_score,
    hiring_signal
  }
};

const rows = $input.all().map(i => i.json);
rows.sort((a,b)=>(b.hiring_score||0)-(a.hiring_score||0));
const top = rows.slice(0,10);
const tr = top.map(r => `<tr><td>${r.startup_name||''}</td><td>${r.startup_description||''}</td><td>${r.investors||''}</td><td>${r.amount_raised||''}</td><td><a href="${r.founder_linkedin||'#'}">LinkedIn</a></td><td>${r.hiring_signal||''} (${r.hiring_score||0})</td></tr>`).join('');
const html = `<h2>Indian Startup Funding Hiring Watchlist</h2><p>Top funded Indian startups most likely to open jobs or internships soon.</p><table border="1" cellpadding="8" cellspacing="0"><tr><th>Startup</th><th>Description</th><th>Investors</th><th>Amount</th><th>Founder LinkedIn</th><th>Hiring Signal</th></tr>${tr}</table><p>Sent automatically by your daily n8n workflow.</p>`;
return [{json:{subject:`Daily Indian Startup Funding Hiring Watchlist - ${new Date().toISOString().slice(0,10)}`, html}}];
